function solve(nums) {
    const MAX_VAL = 100000 + 100005; // Max possible value after modification + buffer
    const isPrime = new Array(MAX_VAL).fill(true);
    isPrime[0] = isPrime[1] = false;

    // Sieve of Eratosthenes to pre-calculate primes up to MAX_VAL
    for (let p = 2; p * p < MAX_VAL; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i < MAX_VAL; i += p)
                isPrime[i] = false;
        }
    }

    /**
     * Checks if a number is prime based on the sieve.
     * @param {number} n
     * @returns {boolean}
     */
    const checkPrime = (n) => {
        if (n >= MAX_VAL) {
            // This should ideally not happen given the constraints and logic,
            // but for safety, perform trial division if outside the sieve range.
            if (n <= 1) return false;
            for (let i = 2; i * i <= n; i++) {
                if (n % i === 0) return false;
            }
            return true;
        }
        return isPrime[n];
    };

    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        let currentNum = nums[i];

        if (i % 2 === 0) {
            // Even index: Must be prime
            let operationsNeeded = 0;
            let nextPrime = currentNum;

            // Find the smallest prime number >= currentNum
            while (true) {
                if (checkPrime(nextPrime)) {
                    break;
                }
                nextPrime++;
            }

            operationsNeeded = nextPrime - currentNum;
            totalOperations += operationsNeeded;
        } else {
            // Odd index: Must be non-prime (composite or 1)
            let operationsNeeded = 0;
            let nextNonPrime = currentNum;

            // Find the smallest non-prime number >= currentNum
            while (true) {
                if (!checkPrime(nextNonPrime)) {
                    // 1 is non-prime by definition (or at least, not prime)
                    // Primes start from 2. 0 and 1 are not prime.
                    if (nextNonPrime > 1) {
                        // It's composite or 1
                        break;
                    }
                    // If nextNonPrime is 1, it's non-prime.
                    if (nextNonPrime === 1) break;

                    // If nextNonPrime is 0 (shouldn't happen with nums[i] >= 1), treat as non-prime.
                    if (nextNonPrime <= 1) break;
                }
                nextNonPrime++;
            }

            operationsNeeded = nextNonPrime - currentNum;
            totalOperations += operationsNeeded;
        }
    }

    return totalOperations;
}

